// === GitHub 파일 업데이트 스크립트 ===
// 아래 YOUR_PAT_HERE 를 본인 PAT 토큰으로 교체 후 실행하세요
const PAT   = "YOUR_PAT_HERE";
const OWNER = "ynyntest1";
const REPO  = "yesanfarm1";
const BRANCH = "main";
const BASE  = "https://api.github.com";
const HDR   = { Authorization: `token ${PAT}`, "Content-Type": "application/json" };

const FILES = [
  { path: "requirements.txt", content: "c3RyZWFtbGl0Pj0xLjMxLjAKcGFuZGFzCm9wZW5weXhsCnhsc3h3cml0ZXIKeGxyZApyZXF1ZXN0cwo=" },
  { path: "views/team_settings.py", content: "" },
  { path: "views/meal_allowance.py", content: "" },
  { path: "components/member_sorter/index.html", content: "" }
];

(async () => {
  for (const f of FILES) {
    // 현재 SHA 조회 (기존 파일 업데이트용)
    const get = await fetch(`${BASE}/repos/${OWNER}/${REPO}/contents/${f.path}?ref=${BRANCH}`, { headers: HDR });
    const body = { message: `update ${f.path}`, content: f.content, branch: BRANCH };
    if (get.ok) body.sha = (await get.json()).sha;

    const put = await fetch(`${BASE}/repos/${OWNER}/${REPO}/contents/${f.path}`, {
      method: "PUT", headers: HDR, body: JSON.stringify(body)
    });
    const res = await put.json();
    console.log(put.ok ? "✅ OK:" : "❌ FAIL:", f.path, put.status);
  }
  console.log("완료! GitHub 새로고침 하세요.");
})();